# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import json
import boto3
import logging
from datetime import datetime
from botocore.exceptions import ClientError

logger = logging.getLogger()
logger.setLevel(logging.INFO)

sns_client = boto3.client('sns')

NOTIFICATION_TYPES = {
    'alert': {
        'subject_prefix': '[ALERT]',
        'default_priority': 'high',
    },
    'info': {
        'subject_prefix': '[INFO]',
        'default_priority': 'low',
    },
    'warning': {
        'subject_prefix': '[WARNING]',
        'default_priority': 'medium',
    },
    'critical': {
        'subject_prefix': '[CRITICAL]',
        'default_priority': 'critical',
    },
    'event': {
        'subject_prefix': '[EVENT]',
        'default_priority': 'medium',
    },
}


def lambda_handler(event, context):
    """
    Lambda handler for publishing messages to SNS topics.
    
    Expected event structure:
    {
        "topic_arn": "arn:aws:sns:us-east-1:123456789012:MyTopic",
        "message": "Your notification message here",
        "subject": "Optional subject line",
        "notification_type": "alert|info|warning|critical|event",
        "attributes": {
            "key1": "value1",
            "key2": "value2"
        },
        "batch_messages": [
            {
                "topic_arn": "arn:aws:sns:...",
                "message": "Message 1",
                "subject": "Subject 1",
                "notification_type": "info"
            }
        ]
    }
    """
    logger.info(f"Received event: {json.dumps(event)}")

    try:
        # Check if this is a batch publish request
        if 'batch_messages' in event and isinstance(event['batch_messages'], list):
            return handle_batch_publish(event['batch_messages'])
        else:
            return handle_single_publish(event)

    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}")
        return build_response(500, {
            'status': 'error',
            'message': f'Unexpected error: {str(e)}'
        })


def handle_single_publish(event):
    """Handle publishing a single message to an SNS topic."""
    # Validate required fields
    topic_arn = event.get('topic_arn')
    message = event.get('message')

    if not topic_arn:
        return build_response(400, {
            'status': 'error',
            'message': 'Missing required field: topic_arn'
        })

    if not message:
        return build_response(400, {
            'status': 'error',
            'message': 'Missing required field: message'
        })

    notification_type = event.get('notification_type', 'info')
    subject = event.get('subject', '')
    attributes = event.get('attributes', {})

    result = publish_message(
        topic_arn=topic_arn,
        message=message,
        subject=subject,
        notification_type=notification_type,
        attributes=attributes
    )

    if result['success']:
        return build_response(200, {
            'status': 'success',
            'message_id': result['message_id'],
            'topic_arn': topic_arn,
            'notification_type': notification_type
        })
    else:
        return build_response(500, {
            'status': 'error',
            'message': result['error']
        })


def handle_batch_publish(messages):
    """Handle publishing multiple messages to SNS topics."""
    results = {
        'successful': [],
        'failed': []
    }

    for idx, msg_config in enumerate(messages):
        topic_arn = msg_config.get('topic_arn')
        message = msg_config.get('message')

        if not topic_arn or not message:
            results['failed'].append({
                'index': idx,
                'error': 'Missing required field: topic_arn or message'
            })
            continue

        notification_type = msg_config.get('notification_type', 'info')
        subject = msg_config.get('subject', '')
        attributes = msg_config.get('attributes', {})

        result = publish_message(
            topic_arn=topic_arn,
            message=message,
            subject=subject,
            notification_type=notification_type,
            attributes=attributes
        )

        if result['success']:
            results['successful'].append({
                'index': idx,
                'message_id': result['message_id'],
                'topic_arn': topic_arn
            })
        else:
            results['failed'].append({
                'index': idx,
                'error': result['error']
            })

    total = len(messages)
    succeeded = len(results['successful'])
    failed = len(results['failed'])

    return build_response(200, {
        'status': 'completed',
        'total': total,
        'succeeded': succeeded,
        'failed': failed,
        'results': results
    })


def publish_message(topic_arn, message, subject='', notification_type='info', attributes=None):
    """
    Publish a message to an SNS topic with proper formatting based on notification type.
    """
    if attributes is None:
        attributes = {}

    try:
        # Get notification type config
        type_config = NOTIFICATION_TYPES.get(notification_type, NOTIFICATION_TYPES['info'])

        # Build the subject line
        if subject:
            full_subject = f"{type_config['subject_prefix']} {subject}"
        else:
            full_subject = f"{type_config['subject_prefix']} Notification"

        # SNS subject has a 100-character limit
        full_subject = full_subject[:100]

        # Build structured message for multi-protocol delivery
        structured_message = build_structured_message(
            message=message,
            notification_type=notification_type,
            type_config=type_config
        )

        # Build message attributes
        sns_message_attributes = build_message_attributes(
            notification_type=notification_type,
            priority=type_config['default_priority'],
            custom_attributes=attributes
        )

        # Publish to SNS
        publish_params = {
            'TopicArn': topic_arn,
            'Message': json.dumps(structured_message),
            'Subject': full_subject,
            'MessageStructure': 'json',
            'MessageAttributes': sns_message_attributes
        }

        response = sns_client.publish(**publish_params)

        message_id = response.get('MessageId', '')
        logger.info(f"Successfully published message {message_id} to {topic_arn}")

        return {
            'success': True,
            'message_id': message_id
        }

    except ClientError as e:
        error_code = e.response['Error']['Code']
        error_message = e.response['Error']['Message']
        logger.error(f"Failed to publish to {topic_arn}: {error_code} - {error_message}")
        return {
            'success': False,
            'error': f'{error_code}: {error_message}'
        }
    except Exception as e:
        logger.error(f"Error publishing message: {str(e)}")
        return {
            'success': False,
            'error': str(e)
        }


def build_structured_message(message, notification_type, type_config):
    """
    Build a structured message for multi-protocol SNS delivery.
    Supports default, email, SMS, Lambda, SQS, and HTTP/S endpoints.
    """
    timestamp = datetime.utcnow().isoformat() + 'Z'

    # Plain text version for default and SMS
    plain_text = f"[{notification_type.upper()}] {message}"

    # Email version with more detail
    email_message = (
        f"--- Event Notification System ---\n\n"
        f"Type: {notification_type.upper()}\n"
        f"Priority: {type_config['default_priority'].upper()}\n"
        f"Timestamp: {timestamp}\n\n"
        f"Message:\n{message}\n\n"
        f"---\n"
        f"This is an automated notification from the Event Notification System."
    )

    # JSON version for Lambda, SQS, and HTTP endpoints
    json_message = json.dumps({
        'notification_type': notification_type,
        'priority': type_config['default_priority'],
        'timestamp': timestamp,
        'message': message,
        'source': 'event-notification-system'
    })

    # SMS version (truncated to 160 chars for SMS best practices)
    sms_message = plain_text[:160]

    structured_message = {
        'default': plain_text,
        'email': email_message,
        'email-json': json_message,
        'sms': sms_message,
        'sqs': json_message,
        'lambda': json_message,
        'http': json_message,
        'https': json_message
    }

    return structured_message


def build_message_attributes(notification_type, priority, custom_attributes=None):
    """
    Build SNS message attributes for filtering and routing.
    """
    if custom_attributes is None:
        custom_attributes = {}

    message_attributes = {
        'notification_type': {
            'DataType': 'String',
            'StringValue': notification_type
        },
        'priority': {
            'DataType': 'String',
            'StringValue': priority
        },
        'timestamp': {
            'DataType': 'String',
            'StringValue': datetime.utcnow().isoformat() + 'Z'
        },
        'source': {
            'DataType': 'String',
            'StringValue': 'event-notification-system'
        }
    }

    # Add custom attributes
    for key, value in custom_attributes.items():
        if isinstance(value, str):
            message_attributes[key] = {
                'DataType': 'String',
                'StringValue': value
            }
        elif isinstance(value, (int, float)):
            message_attributes[key] = {
                'DataType': 'Number',
                'StringValue': str(value)
            }

    return message_attributes


def build_response(status_code, body):
    """Build a standardized response."""
    return {
        'statusCode': status_code,
        'body': body,
        'timestamp': datetime.utcnow().isoformat() + 'Z'
    }